mapper.select:
SELECT * FROM goods
WHERE status = 2

    AND (title LIKE '%' + #{query.keyword} + '%' OR description LIKE '%' + #{query.keyword} + '%')


    AND category = #{query.category}


    AND condition_level = #{query.conditionLevel}


    AND price >= #{query.priceMin}


    AND price <= #{query.priceMax}


    ORDER BY price ASC
    ORDER BY price DESC
    ORDER BY view_count DESC
    ORDER BY created_at DESC
